import { InlineSearch, useSearchIndex } from './components/search/SearchOverlay'

const results = useSearchIndex({
  items: posts,
  query,
  getText: (post) => [post.title, post.body, post.authorName],
})

<InlineSearch
  query={query}
  onQueryChange={setQuery}
  items={results.map((post) => ({
    id: post.id,
    title: post.title,
    subtitle: post.authorName,
    description: post.body,
  }))}
  onSelect={(item) => openPost(item.id)}
  placeholder="Search posts..."
/>
